mapper.select:
SELECT ID, WAREHOUSE_OUT_NO, WAREHOUSE_OUT_TITLE, WAREHOUSE_ID, WAREHOUSE_NAME, DEPT_ID, DEPT_NAME, RECEIVER_ID, RECEIVER_NAME, WAREHOUSE_OUT_TYPE_CODE, WAREHOUSE_OUT_TYPE_NAME, SOURCE_BIZ_ID, SOURCE_BIZ_NO, STATUS, CONFIRM_BY, CONFIRM_BY_NAME, CONFIRM_TIME, CHECK_ID, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM E_MAT_WAREHOUSE_OUT
AND WAREHOUSE_OUT_NO LIKE #{warehouseOutNoPattern}
AND WAREHOUSE_OUT_TITLE LIKE #{warehouseOutTitlePattern}
AND DEPT_ID = #{deptId}
AND WAREHOUSE_NAME = #{warehouseName}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MAT_WAREHOUSE_OUT
WHERE WAREHOUSE_OUT_NO = #{warehouseOutNo}

    AND ID != #{id}
